//블럭선택 및 복사
mygrid{G.GRPID}.enableBlockSelection(true);
mygrid{G.GRPID}.attachEvent("onKeyPress",function(code,ctrl,shift){
	alog("onKeyPress.......code=" + code + ", ctrl=" + ctrl + ", shift=" + shift);

	//셀편집모드 아닐때만 블록처리
	if(!mygrid{G.GRPID}.editor){
		mygrid{G.GRPID}.setCSVDelimiter("	");
		if(code==67&&ctrl){
			mygrid{G.GRPID}.copyBlockToClipboard();

			var top_row_idx = mygrid{G.GRPID}.getSelectedBlock().LeftTopRow;
			var bottom_row_idx = mygrid{G.GRPID}.getSelectedBlock().RightBottomRow;
			var copyRowCnt = bottom_row_idx-top_row_idx+1;
			msgNotice( copyRowCnt + "개의 행이 클립보드에 복사되었습니다.",2);

		}
		if(code==86&&ctrl){
			mygrid{G.GRPID}.pasteBlockFromClipboard();

			//row상태 변경
			var top_row_idx = mygrid{G.GRPID}.getSelectedBlock().LeftTopRow;
			var bottom_row_idx = mygrid{G.GRPID}.getSelectedBlock().RightBottomRow;
			for(j=top_row_idx;j<=bottom_row_idx;j++){
				var rowID = mygrid{G.GRPID}.getRowId(j);
				RowEditStatus = mygrid{G.GRPID}.getUserData(rowID,"!nativeeditor_status");
				if(RowEditStatus == ""){
					mygrid{G.GRPID}.setUserData(rowID,"!nativeeditor_status","updated");
					mygrid{G.GRPID}.setRowTextBold(rowID);
				}
			}
		}
		return true;
	}else{
		return false;
	}
});

